sql:
SELECT helm_name, crew_name, AVG(points) AS average_points
FROM race_results
GROUP BY helm_name, crew_name;

SELECT sailor_id, helm_name, crew_name, club 
FROM sailors 
WHERE NOT EXISTS (SELECT 1 FROM event_registrations WHERE sailors.sailor_id = event_registrations.sailor_id);

SELECT helm_name, crew_name, club
FROM sailors
ORDER BY crew_name;

external_knowledge:
- "Top five with the highest average points" refers to the sailing classes that have the highest average points scored when considering all their race results. ;
- "Impressive performance" in this context is quantified by the class with the highest average points among the selected top five classes. ;
- "Performance" is measured by the average points scored in races. ;

sql:
SELECT helm_name, crew_name, COUNT(race_id) AS race_count, AVG(laps) AS avg_laps
FROM race_results
GROUP BY helm_name, crew_name;

SELECT sailors.sailor_id, sailors.helm_name 
FROM sailors
JOIN event_registrations ON sailors.sailor_id = event_registrations.sailor_id;

SELECT COUNT(*)
FROM sailing_classes
WHERE min_boat_length <= 12;

SELECT fleet, AVG(points) AS average_points
FROM race_results
GROUP BY fleet;

SELECT e.race_id, s.helm_name, s.crew_name
FROM sailors s
INNER JOIN event_registrations e ON s.sailor_id = e.sailor_id;

SELECT fleet, AVG(points) AS avg_points
FROM race_results
GROUP BY fleet;
